impl Solution { pub fn minimum_cost(black_src: String, black_tgt: String, black_orig: Vec<char>, black_chg: Vec<char>, black_cost: Vec<i32>) -> i64 { let mut black_dist = vec![vec![i64::MAX / 2; 26]; 26]; for i in 0..26 { black_dist[i][i] = 0; } for i in 0..black_orig.len() { let (u, v) = ((black_orig[i] as usize - 97), (black_chg[i] as usize - 97)); black_dist[u][v] = black_dist[u][v].min(black_cost[i] as i64); } for k in 0..26 { for i in 0..26 { for j in 0..26 { black_dist[i][j] = black_dist[i][j].min(black_dist[i][k] + black_dist[k][j]); } } } let (mut black_ans, black_s, black_t) = (0i64, black_src.as_bytes(), black_tgt.as_bytes()); for i in 0..black_s.len() { let d = black_dist[(black_s[i]-97) as usize][(black_t[i]-97) as usize]; if d >= i64::MAX / 2 { return -1; } black_ans += d; } black_ans } }